import { ipcMain, shell, BrowserWindow } from 'electron';
import { GitHubAuthService } from '../services/GitHubAuthService';
import { GitHubApiService } from '../services/GitHubApiService';
import { serverGitAccountService } from '../services/ServerGitAccountService';
import { ApiResult } from './types';
import { logger } from '../logger';
import { db } from '../db';

/**
 * Register GitHub IPC handlers
 */
export function registerGitHubHandlers(
  authService: GitHubAuthService,
  apiService: GitHubApiService
): void {
  console.log('[IPC] Registering GitHub handlers');

  /**
   * Start GitHub Device Flow authentication
   */
  ipcMain.handle('github:start-auth', async (): Promise<ApiResult<{
    userCode: string;
    verificationUri: string;
    expiresIn: number;
  }>> => {
    try {
      const deviceCode = await authService.startDeviceFlow();

      // Open verification URL in browser
      await shell.openExternal(deviceCode.verification_uri);

      return {
        success: true,
        data: {
          userCode: deviceCode.user_code,
          verificationUri: deviceCode.verification_uri,
          expiresIn: deviceCode.expires_in,
        },
      };

    } catch (error: any) {
      console.error('[IPC] Failed to start GitHub auth:', error);
      return {
        success: false,
        error: error.message || 'Failed to start GitHub authentication',
      };
    }
  });

  /**
   * Check authentication status and get current user
   */
  ipcMain.handle('github:check-auth', async (): Promise<ApiResult<{
    authenticated: boolean;
    user: any | null;
  }>> => {
    try {
      const user = await authService.getCurrentUser();

      return {
        success: true,
        data: {
          authenticated: !!user,
          user,
        },
      };

    } catch (error: any) {
      console.error('[IPC] Failed to check GitHub auth:', error);
      return {
        success: true,
        data: {
          authenticated: false,
          user: null,
        },
      };
    }
  });

  /**
   * Get repositories for authenticated user
   */
  ipcMain.handle('github:get-repos', async (): Promise<ApiResult<any[]>> => {
    try {
      const repos = await apiService.getRepositories({
        sort: 'updated',
        per_page: 100,
      });

      return {
        success: true,
        data: repos,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to get GitHub repositories:', error);
      return {
        success: false,
        error: error.message || 'Failed to fetch repositories',
      };
    }
  });

  /**
   * Detect framework for a specific repository
   */
  ipcMain.handle('github:detect-framework', async (
    _event,
    owner: string,
    repo: string
  ): Promise<ApiResult<string | null>> => {
    try {
      const framework = await apiService.detectFramework(owner, repo);

      return {
        success: true,
        data: framework,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to detect framework:', error);
      return {
        success: false,
        error: error.message || 'Failed to detect framework',
      };
    }
  });

  /**
   * Get branches for a repository
   */
  ipcMain.handle('github:get-branches', async (
    _event,
    owner: string,
    repo: string
  ): Promise<ApiResult<Array<{ name: string; protected: boolean }>>> => {
    try {
      const branches = await apiService.getBranches(owner, repo);

      return {
        success: true,
        data: branches,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to get branches:', error);
      return {
        success: false,
        error: error.message || 'Failed to fetch branches',
      };
    }
  });

  /**
   * Sign out from GitHub
   */
  ipcMain.handle('github:sign-out', async (): Promise<ApiResult<void>> => {
    try {
      await authService.signOut();

      return {
        success: true,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to sign out:', error);
      return {
        success: false,
        error: error.message || 'Failed to sign out',
      };
    }
  });

  /**
   * Upload SSH public key to GitHub
   */
  ipcMain.handle('github:upload-ssh-key', async (
    _event,
    title: string,
    publicKey: string
  ): Promise<ApiResult<void>> => {
    try {
      await apiService.uploadSSHKey(title, publicKey);

      return {
        success: true,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to upload SSH key:', error);
      return {
        success: false,
        error: error.message || 'Failed to upload SSH key',
      };
    }
  });

  /**
   * List SSH keys on GitHub
   */
  ipcMain.handle('github:list-ssh-keys', async (): Promise<ApiResult<Array<{
    id: number;
    title: string;
    key: string;
  }>>> => {
    try {
      const keys = await apiService.listSSHKeys();

      return {
        success: true,
        data: keys,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to list SSH keys:', error);
      return {
        success: false,
        error: error.message || 'Failed to list SSH keys',
      };
    }
  });

  /**
   * Delete SSH key from GitHub
   */
  ipcMain.handle('github:delete-ssh-key', async (
    _event,
    keyId: number
  ): Promise<ApiResult<void>> => {
    try {
      await apiService.deleteSSHKey(keyId);

      return {
        success: true,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to delete SSH key:', error);
      return {
        success: false,
        error: error.message || 'Failed to delete SSH key',
      };
    }
  });

  /**
   * List all connected GitHub accounts
   */
  ipcMain.handle('github:list-accounts', async (): Promise<ApiResult<any[]>> => {
    try {
      const accounts = await authService.listAccounts();

      return {
        success: true,
        data: accounts,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to list accounts:', error);
      return {
        success: false,
        error: error.message || 'Failed to list accounts',
      };
    }
  });

  /**
   * Get active GitHub account
   */
  ipcMain.handle('github:get-active-account', async (): Promise<ApiResult<string | null>> => {
    try {
      const activeAccount = await authService.getActiveAccount();

      return {
        success: true,
        data: activeAccount,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to get active account:', error);
      return {
        success: false,
        error: error.message || 'Failed to get active account',
      };
    }
  });

  /**
   * Switch to a different GitHub account
   */
  ipcMain.handle('github:switch-account', async (
    _event,
    username: string
  ): Promise<ApiResult<void>> => {
    try {
      await authService.switchAccount(username);

      return {
        success: true,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to switch account:', error);
      return {
        success: false,
        error: error.message || 'Failed to switch account',
      };
    }
  });

  /**
   * Sign out from a specific account
   */
  ipcMain.handle('github:sign-out-account', async (
    _event,
    username: string
  ): Promise<ApiResult<void>> => {
    try {
      await authService.signOutAccount(username);

      return {
        success: true,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to sign out account:', error);
      return {
        success: false,
        error: error.message || 'Failed to sign out account',
      };
    }
  });

  /**
   * Get repositories for a specific account
   */
  ipcMain.handle('github:get-repos-for-account', async (
    _event,
    username: string
  ): Promise<ApiResult<any[]>> => {
    try {
      const repos = await apiService.getRepositories({
        sort: 'updated',
        per_page: 100,
        username,
      });

      return {
        success: true,
        data: repos,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to get repositories for account:', error);
      return {
        success: false,
        error: error.message || 'Failed to fetch repositories',
      };
    }
  });

  // Listen to auth service events and forward to renderer
  authService.on('authenticated', async (data) => {
    console.log('[IPC] Broadcasting authentication success to renderers');

    let gitAccountId: string | null = null;
    try {
      const username = data.username || data.user?.login;

      if (username) {
        const accountInfo = {
          username,
          id: data.user?.id ?? Date.now(),
          name: data.user?.name ?? null,
          email: data.user?.email ?? null,
          avatar_url: data.user?.avatar_url ?? '',
        };

        gitAccountId = await serverGitAccountService.syncAccountFromOAuth(
          accountInfo,
          data.token,
          'github',
          data.scopes
        );

        console.log('[IPC] Synced GitHub account, gitAccountId:', gitAccountId);
      }
    } catch (error) {
      console.error('[IPC] Failed to sync GitHub account with database:', error);
    }

    const payload = {
      ...data,
      username: data.username || data.user?.login || null,
      gitAccountId,
    };

    // Broadcast to all windows
    BrowserWindow.getAllWindows().forEach(win => {
      win.webContents.send('github:authenticated', payload);
    });
  });

  authService.on('error', (error) => {
    console.log('[IPC] Broadcasting authentication error to renderers');
    BrowserWindow.getAllWindows().forEach(win => {
      win.webContents.send('github:auth-error', { error: error.message });
    });
  });

  authService.on('signed-out', () => {
    console.log('[IPC] Broadcasting sign-out to renderers');
    BrowserWindow.getAllWindows().forEach(win => {
      win.webContents.send('github:signed-out');
    });
  });

  authService.on('account-switched', (data) => {
    console.log('[IPC] Broadcasting account switch to renderers');
    BrowserWindow.getAllWindows().forEach(win => {
      win.webContents.send('github:account-switched', data);
    });
  });

  authService.on('account-removed', (data) => {
    console.log('[IPC] Broadcasting account removal to renderers');
    BrowserWindow.getAllWindows().forEach(win => {
      win.webContents.send('github:account-removed', data);
    });
  });

  // ============================================================================
  // SERVER-SCOPED GIT ACCOUNT HANDLERS
  // ============================================================================

  /**
   * Get all Git accounts linked to a specific server
   */
  ipcMain.handle('github:get-server-accounts', async (
    _event,
    serverId: string
  ): Promise<ApiResult<any[]>> => {
    try {
      const accounts = await serverGitAccountService.getAccountsForServer(serverId);

      return {
        success: true,
        data: accounts,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to get server accounts:', error);
      return {
        success: false,
        error: error.message || 'Failed to get server accounts',
      };
    }
  });

  /**
   * Get all global Git accounts (for adding to servers)
   */
  ipcMain.handle('github:get-all-accounts', async (): Promise<ApiResult<any[]>> => {
    try {
      const accounts = await serverGitAccountService.getAllGitAccounts();

      return {
        success: true,
        data: accounts,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to get all git accounts:', error);
      return {
        success: false,
        error: error.message || 'Failed to get all git accounts',
      };
    }
  });

  /**
   * Link a Git account to a server
   */
  ipcMain.handle('github:link-to-server', async (
    _event,
    serverId: string,
    gitAccountId: string,
    isDefault: boolean = false
  ): Promise<ApiResult<{ accounts: any[]; defaultAccount: any | null }>> => {
    try {
      logger.info('[IPC] link-to-server request', { serverId, gitAccountId, isDefault });
      await serverGitAccountService.linkAccountToServer(serverId, gitAccountId, isDefault);

      const [accounts, defaultAccount] = await Promise.all([
        serverGitAccountService.getAccountsForServer(serverId),
        serverGitAccountService.getDefaultAccountForServer(serverId),
      ]);

      logger.info('[IPC] link-to-server response', {
        serverId,
        accountsCount: accounts.length,
        defaultAccount: defaultAccount?.username || null,
        accounts: accounts.map(a => ({ id: a.gitAccountId, username: a.username }))
      });

      return {
        success: true,
        data: {
          accounts,
          defaultAccount,
        },
      };

    } catch (error: any) {
      logger.error('[IPC] Failed to link account to server:', error);
      return {
        success: false,
        error: error.message || 'Failed to link account to server',
      };
    }
  });

  /**
   * Unlink a Git account from a server
   */
  ipcMain.handle('github:unlink-from-server', async (
    _event,
    serverId: string,
    gitAccountId: string
  ): Promise<ApiResult<{ accounts: any[]; defaultAccount: any | null }>> => {
    try {
      logger.info('[IPC] unlink-from-server request', { serverId, gitAccountId });
      await serverGitAccountService.unlinkAccountFromServer(serverId, gitAccountId);

      // Ensure default is cleared if we removed it
      let defaultAccount = await serverGitAccountService.getDefaultAccountForServer(serverId);
      if (defaultAccount?.gitAccountId === gitAccountId) {
        defaultAccount = null;
      }

      const accounts = await serverGitAccountService.getAccountsForServer(serverId);

      return {
        success: true,
        data: {
          accounts,
          defaultAccount,
        },
      };

    } catch (error: any) {
      console.error('[IPC] Failed to unlink account from server:', error);
      return {
        success: false,
        error: error.message || 'Failed to unlink account from server',
      };
    }
  });

  /**
   * Set an account as default for a server
   */
  ipcMain.handle('github:set-server-default', async (
    _event,
    serverId: string,
    gitAccountId: string
  ): Promise<ApiResult<void>> => {
    try {
      await serverGitAccountService.setDefaultAccount(serverId, gitAccountId);

      return {
        success: true,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to set default account:', error);
      return {
        success: false,
        error: error.message || 'Failed to set default account',
      };
    }
  });

  /**
   * Get default Git account for a server
   */
  ipcMain.handle('github:get-server-default', async (
    _event,
    serverId: string
  ): Promise<ApiResult<any | null>> => {
    try {
      const account = await serverGitAccountService.getDefaultAccountForServer(serverId);

      return {
        success: true,
        data: account,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to get default account:', error);
      return {
        success: false,
        error: error.message || 'Failed to get default account',
      };
    }
  });

  /**
   * Get repositories for a server's default account
   */
  ipcMain.handle('github:get-server-repos', async (
    _event,
    serverId: string
  ): Promise<ApiResult<any[]>> => {
    try {
      const defaultAccount = await serverGitAccountService.getDefaultAccountForServer(serverId);

      if (!defaultAccount) {
        return {
          success: false,
          error: 'No default Git account set for this server',
        };
      }

      const repos = await apiService.getRepositories({
        sort: 'updated',
        per_page: 100,
        username: defaultAccount.username,
      });

      return {
        success: true,
        data: repos,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to get server repositories:', error);
      return {
        success: false,
        error: error.message || 'Failed to fetch server repositories',
      };
    }
  });

  /**
   * Get git account ID by username
   */
  ipcMain.handle('github:get-account-id-by-username', async (
    _event,
    username: string,
    provider: 'github' | 'gitlab' = 'github'
  ): Promise<ApiResult<string | null>> => {
    try {
      const accountId = await serverGitAccountService.getGitAccountIdByUsername(username, provider);

      return {
        success: true,
        data: accountId,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to get git account ID by username:', error);
      return {
        success: false,
        error: error.message || 'Failed to get git account ID',
      };
    }
  });

  /**
   * Analyze a repository for Docker deployment
   * Checks for docker-compose.yml, Dockerfile, and detects framework
   */
  ipcMain.handle('github:analyze-repo-for-docker', async (
    _event,
    owner: string,
    repo: string
  ): Promise<ApiResult<{
    hasDockerCompose: boolean;
    hasDockerfile: boolean;
    dockerComposePath: string | null;
    dockerComposeContent: string | null;
    dockerfileContent: string | null;
    framework: string | null;
    packageManager: 'npm' | 'yarn' | 'pnpm' | null;
    suggestedPort: number;
  }>> => {
    try {
      const analysis = await apiService.analyzeRepoForDocker(owner, repo);

      return {
        success: true,
        data: analysis,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to analyze repository for Docker:', error);
      return {
        success: false,
        error: error.message || 'Failed to analyze repository',
      };
    }
  });

  /**
   * Create a new GitHub repository
   */
  ipcMain.handle('github:createRepo', async (
    _event,
    options: {
      accountId: string;
      name: string;
      description?: string;
      private?: boolean;
    }
  ): Promise<ApiResult<any>> => {
    try {
      // Get the account to find the username
      const account = db.prepare(`
        SELECT username FROM git_accounts WHERE id = ?
      `).get(options.accountId) as { username: string } | undefined;

      if (!account) {
        return {
          success: false,
          error: 'GitHub account not found',
        };
      }

      const repo = await apiService.createRepo({
        name: options.name,
        description: options.description,
        private: options.private ?? true,
        username: account.username,
      });

      return {
        success: true,
        data: repo,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to create repository:', error);
      return {
        success: false,
        error: error.message || 'Failed to create repository',
      };
    }
  });

  /**
   * Commit multiple files to a repository
   */
  ipcMain.handle('github:commitFiles', async (
    _event,
    options: {
      accountId: string;
      owner: string;
      repo: string;
      branch: string;
      files: Array<{ path: string; content: string }>;
      message: string;
    }
  ): Promise<ApiResult<void>> => {
    try {
      // Get the account to find the username
      const account = db.prepare(`
        SELECT username FROM git_accounts WHERE id = ?
      `).get(options.accountId) as { username: string } | undefined;

      if (!account) {
        return {
          success: false,
          error: 'GitHub account not found',
        };
      }

      await apiService.createOrUpdateMultipleFiles(
        options.owner,
        options.repo,
        options.branch,
        options.files,
        options.message,
        account.username
      );

      return {
        success: true,
      };

    } catch (error: any) {
      console.error('[IPC] Failed to commit files:', error);
      return {
        success: false,
        error: error.message || 'Failed to commit files',
      };
    }
  });

  console.log('[IPC] GitHub handlers registered');
}
